final_files.sections/testimonial-cards.liquid:
{% liquid
  assign columns = section.settings.columns
  assign mobile_columns = section.settings.mobile_columns
  assign testimonials = section.blocks
%}

<div class="section-background color-{{ section.settings.color_scheme }}"></div>

<div
  class="
    section
    section--{{ section.settings.section_width }}
    color-{{ section.settings.color_scheme }}
    spacing-style
    gap-style
  "
  style="
    {%- render 'spacing-style', settings: section.settings -%}
    {%- render 'gap-style', value: section.settings.gap -%}
  "
>
  {% if section.settings.heading != blank %}
    <div class="section__heading">
      <{{ section.settings.heading_tag }} class="heading">
        {{ section.settings.heading | escape }}
      </{{ section.settings.heading_tag }}>
    </div>
  {% endif %}

  {% if testimonials.size > 0 %}
    <div 
      class="testimonial-cards__grid"
      style="
        --grid-columns: {{ columns }};
        --grid-columns-mobile: {{ mobile_columns }};
        --columns-gap: {{ section.settings.columns_gap }}px;
        --rows-gap: {{ section.settings.rows_gap }}px;
      "
    >
      {% for block in testimonials %}
        {% assign testimonial = block.settings %}
        <div class="testimonial-card" {{ block.shopify_attributes }}>
          {% if testimonial.quote != blank %}
            <div class="testimonial-card__quote">
              <blockquote>{{ testimonial.quote }}</blockquote>
            </div>
          {% endif %}

          {% if testimonial.rating > 0 %}
            <div class="testimonial-card__rating">
              {% for i in (1..5) %}
                {% if i <= testimonial.rating %}
                  <svg class="star star--filled" viewBox="0 0 20 20" fill="currentColor">
                    <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"/>
                  </svg>
                {% else %}
                  <svg class="star star--empty" viewBox="0 0 20 20" stroke="currentColor" fill="none">
                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="1" d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"/>
                  </svg>
                {% endif %}
              {% endfor %}
            </div>
          {% endif %}

          {% if testimonial.customer_name != blank %}
            <div class="testimonial-card__author">
              <cite>{{ testimonial.customer_name | escape }}</cite>
            </div>
          {% endif %}
        </div>
      {% endfor %}
    </div>
  {% endif %}
</div>

{% stylesheet %}
  .testimonial-cards__grid {
    display: grid;
    grid-template-columns: repeat(var(--grid-columns-mobile), 1fr);
    gap: var(--rows-gap) var(--columns-gap);
  }

  @media screen and (min-width: 750px) {
    .testimonial-cards__grid {
      grid-template-columns: repeat(var(--grid-columns), 1fr);
    }
  }

  .testimonial-card {
    background: rgb(var(--color-background));
    border: 1px solid rgba(var(--color-foreground), 0.1);
    border-radius: var(--border-radius);
    padding: 2rem;
    display: flex;
    flex-direction: column;
    gap: 1rem;
    height: 100%;
  }

  .testimonial-card__quote blockquote {
    font-style: italic;
    margin: 0;
    padding: 0;
    font-size: 1.1rem;
    line-height: 1.5;
  }

  .testimonial-card__rating {
    display: flex;
    gap: 0.25rem;
    align-items: center;
  }

  .star {
    width: 1rem;
    height: 1rem;
    color: #fbbf24;
  }

  .star--empty {
    color: rgba(var(--color-foreground), 0.3);
  }

  .testimonial-card__author {
    margin-top: auto;
    font-weight: 600;
  }

  .testimonial-card__author cite {
    font-style: normal;
  }

  .section__heading {
    text-align: center;
    margin-bottom: 2rem;
  }

  .section__heading .heading {
    margin: 0;
  }
{% endstylesheet %}

