final_files.sections/countdown-banner.liquid:
{%- style -%}
  .countdown-banner-{{ section.id }} {
    background-color: {{ section.settings.background_color | default: '#000000' }};
    color: {{ section.settings.text_color | default: '#ffffff' }};
  }

  .countdown-banner__container {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
    padding: 2rem 1rem;
  }

  .countdown-banner__heading {
    font-size: 1.5rem;
    margin-bottom: 1rem;
    font-weight: bold;
  }

  .countdown-banner__timer {
    display: flex;
    gap: 1rem;
    justify-content: center;
    flex-wrap: wrap;
  }

  .countdown-banner__time-unit {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 60px;
  }

  .countdown-banner__number {
    font-size: 2rem;
    font-weight: bold;
    line-height: 1;
  }

  .countdown-banner__label {
    font-size: 0.875rem;
    text-transform: uppercase;
    margin-top: 0.25rem;
  }

  @media screen and (max-width: 749px) {
    .countdown-banner__heading {
      font-size: 1.25rem;
    }

    .countdown-banner__number {
      font-size: 1.5rem;
    }

    .countdown-banner__timer {
      gap: 0.75rem;
    }

    .countdown-banner__time-unit {
      min-width: 50px;
    }
  }
{%- endstyle -%}

<div class="countdown-banner-{{ section.id }}" data-testid="countdown-banner-{{ section.id }}">
  <div class="countdown-banner__container">
    {%- if section.settings.heading != blank -%}
      <h2 class="countdown-banner__heading">{{ section.settings.heading | escape }}</h2>
    {%- endif -%}

    <div class="countdown-banner__timer" id="countdown-timer-{{ section.id }}">
      <div class="countdown-banner__time-unit">
        <div class="countdown-banner__number" data-days>00</div>
        <div class="countdown-banner__label">Days</div>
      </div>
      <div class="countdown-banner__time-unit">
        <div class="countdown-banner__number" data-hours>00</div>
        <div class="countdown-banner__label">Hours</div>
      </div>
      <div class="countdown-banner__time-unit">
        <div class="countdown-banner__number" data-minutes>00</div>
        <div class="countdown-banner__label">Minutes</div>
      </div>
      <div class="countdown-banner__time-unit">
        <div class="countdown-banner__number" data-seconds>00</div>
        <div class="countdown-banner__label">Seconds</div>
      </div>
    </div>
  </div>
</div>

<script>
  (function() {
    const sectionId = '{{ section.id }}';
    const endDate = '{{ section.settings.end_date }}';

    if (!endDate) return;

    const timer = document.getElementById(`countdown-timer-${sectionId}`);
    if (!timer) return;

    const daysElement = timer.querySelector('[data-days]');
    const hoursElement = timer.querySelector('[data-hours]');
    const minutesElement = timer.querySelector('[data-minutes]');
    const secondsElement = timer.querySelector('[data-seconds]');

    function updateCountdown() {
      const now = new Date().getTime();
      const targetDate = new Date(endDate).getTime();
      const difference = targetDate - now;

      if (difference > 0) {
        const days = Math.floor(difference / (1000 * 60 * 60 * 24));
        const hours = Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
        const minutes = Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60));
        const seconds = Math.floor((difference % (1000 * 60)) / 1000);

        daysElement.textContent = String(days).padStart(2, '0');
        hoursElement.textContent = String(hours).padStart(2, '0');
        minutesElement.textContent = String(minutes).padStart(2, '0');
        secondsElement.textContent = String(seconds).padStart(2, '0');
      } else {
        // Timer has expired
        daysElement.textContent = '00';
        hoursElement.textContent = '00';
        minutesElement.textContent = '00';
        secondsElement.textContent = '00';
      }
    }

    // Update immediately
    updateCountdown();

    // Update every second
    setInterval(updateCountdown, 1000);
  })();
</script>

{% schema %}
