final_files.sections/newsletter-popup.liquid:
{% liquid
  assign popup_id = 'newsletter-popup-' | append: section.id
  assign delay_ms = section.settings.delay_seconds | times: 1000
%}

<div
  id="{{ popup_id }}"
  class="newsletter-popup"
  style="display: none;"
  data-testid="newsletter-popup-{{ section.id }}"
  data-delay="{{ delay_ms }}"
>
  <div class="newsletter-popup__overlay">
    <div class="newsletter-popup__modal color-{{ section.settings.color_scheme }}">
      <button
        type="button"
        class="newsletter-popup__close"
        aria-label="{{ 'actions.close' | t }}"
        onclick="closeNewsletterPopup('{{ popup_id }}')"
      >
        <svg
          viewBox="0 0 20 20"
          xmlns="http://www.w3.org/2000/svg"
          focusable="false"
          aria-hidden="true"
          class="newsletter-popup__close-icon"
        >
          {% render 'icon', icon: 'close' %}
        </svg>
      </button>

      <div class="newsletter-popup__content">
        {% if section.settings.heading != blank %}
          <h2 class="newsletter-popup__heading {{ section.settings.heading_preset }}">
            {{ section.settings.heading | escape }}
          </h2>
        {% endif %}

        {% if section.settings.description != blank %}
          <div class="newsletter-popup__description rte">
            {{ section.settings.description }}
          </div>
        {% endif %}

        {% assign form_id = 'NewsletterPopup-' | append: section.id %}
        {%- form 'customer', class: 'newsletter-popup__form' -%}
          <input
            name="contact[id]"
            type="hidden"
            value="{{ form_id }}"
          >

          <div class="newsletter-popup__input-group">
            <label
              for="EmailInput-{{ section.id }}"
              class="visually-hidden"
            >
              {{ 'blocks.email_signup.label' | t }}
            </label>
            <input
              id="EmailInput-{{ section.id }}"
              class="newsletter-popup__input"
              type="email"
              name="contact[email]"
              autocorrect="off"
              autocapitalize="off"
              autocomplete="email"
              placeholder="{{ 'blocks.email_signup.placeholder' | t }}"
              required
              {% if form.errors and form.id == form_id %}
                autofocus
                aria-invalid="true"
                aria-describedby="Newsletter-popup__message-error-{{ section.id }}"
              {% elsif form.posted_successfully? and form.id == form_id %}
                aria-describedby="Newsletter-popup__message-success-{{ section.id }}"
              {% endif %}
            >
            <button
              type="submit"
              class="newsletter-popup__button button-primary"
            >
              {{ section.settings.button_label | default: 'Subscribe' }}
            </button>
          </div>

          {%- if form.errors and form.id == form_id -%}
            <div
              id="Newsletter-popup__message-error-{{ section.id }}"
              class="newsletter-popup__message newsletter-popup__message--error"
              tabindex="-1"
            >
              <svg
                viewBox="0 0 20 20"
                xmlns="http://www.w3.org/2000/svg"
                focusable="false"
                aria-hidden="true"
                class="icon-error"
              >
                {%- render 'icon', icon: 'error'  -%}
              </svg>
              {{- form.errors.translated_fields.email | capitalize }}
              {{ form.errors.messages.email -}}
            </div>
          {%- endif -%}

          {%- if form.posted_successfully? and form.id == form_id -%}
            <div
              id="Newsletter-popup__message-success-{{ section.id }}"
              class="newsletter-popup__message newsletter-popup__message--success"
              tabindex="-1"
            >
              <span class="svg-wrapper icon-success">
                {{ 'icon-checkmark.svg' | inline_asset_content }}
              </span>
              <p class="newsletter-popup__message-text">{{ 'blocks.email_signup.success' | t }}</p>
            </div>
          {%- endif -%}
        {%- endform -%}
      </div>
    </div>
  </div>
</div>

{% stylesheet %}
  .newsletter-popup {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: 9999;
  }

  .newsletter-popup__overlay {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-color: rgba(0, 0, 0, 0.7);
    display: flex;
