<script>
  // Newsletter popup functionality
  function showNewsletterPopup(popupId, delay = 0) {
    // Check if user has already seen the popup or subscribed
    const storageKey = `newsletter-popup-${popupId}-dismissed`;
    const hasSeenPopup = localStorage.getItem(storageKey);

    if (hasSeenPopup) {
      return;
    }

    setTimeout(() => {
      const popup = document.getElementById(popupId);
      if (popup) {
        popup.style.display = 'block';
        document.body.style.overflow = 'hidden';

        // Track that popup was shown
        localStorage.setItem(storageKey, 'true');

        // Auto-focus on email input for accessibility
        const emailInput = popup.querySelector('input[type="email"]');
        if (emailInput) {
          emailInput.focus();
        }
      }
    }, delay);
  }

  function closeNewsletterPopup(popupId) {
    const popup = document.getElementById(popupId);
    if (popup) {
      popup.style.display = 'none';
      document.body.style.overflow = '';
    }
  }

  // Initialize popup on page load
  document.addEventListener('DOMContentLoaded', function() {
    const popup = document.querySelector('[data-testid^="newsletter-popup-"]');
    if (popup) {
      const popupId = popup.id;
      const delay = parseInt(popup.dataset.delay) || 0;

      showNewsletterPopup(popupId, delay);

      // Close popup when clicking overlay
      popup.querySelector('.newsletter-popup__overlay').addEventListener('click', function(e) {
        if (e.target === this) {
          closeNewsletterPopup(popupId);
        }
      });

      // Close popup with Escape key
      document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape') {
          closeNewsletterPopup(popupId);
        }
      });

      // Hide popup after successful submission
      const successMessage = popup.querySelector('.newsletter-popup__message--success');
      if (successMessage) {
        setTimeout(() => {
          closeNewsletterPopup(popupId);
        }, 3000);
      }
    }
  });
</script>

